class Solution {
    public int minSwapsCouples(int[] row) {
        int n = row.length / 2;
        int[] pos = new int[2 * n];
        for (int i = 0; i < 2 * n; i++) {
            pos[row[i]] = i;
        }
        int res = 0;
        for (int i = 0; i < 2 * n; i += 2) {
            if (row[i] != i / 2 * 2 && row[i + 1] != i / 2 * 2 + 1) {
                int t = pos[i / 2 * 2 + 1];
                pos[row[i + 1]] = pos[i / 2 * 2 + 1];
                pos[row[t]] = i + 1;
                int temp = row[i + 1];
                row[i + 1] = row[t];
                row[t] = temp;
                res++;
            }
        }
        return res;
    }
}
